        margin-top: 0.5rem;
        margin-bottom: 1rem;
        gap: 12px;
        padding: 0 10px;
        box-sizing: border-box;
    }
    .postcards-parent-loading-container {
        position: relative;
        top: 60px;
        display: flex;
        justify-content: center;
        align-items: center;
        flex-direction: column;
        width: 100%;
        height: 100vh;
    }
    .cards{
        border-radius: 10px;
